-- Enrichment marathon batch: apiary.io, ApiFlash, Apify, APITemplate.io, APIVerve, Apollo GraphQL, App Annie, appcircle.io

-- ── apiary.io ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Apiary was an API design, mock server, and documentation platform built around the open-source API Blueprint format. It was acquired by Oracle in 2017 and is now being wound down, with Oracle shutting the service off in September 2026.$q$, short_description),
  pricing_model = COALESCE($q$free$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(2011, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$San Francisco, California, USA (originally); now operated as part of Oracle Corporation$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Apiary.io Review 2026: History, Features and Oracle Shutdown$q$, seo_title),
  seo_meta_description = COALESCE($q$Apiary.io was an API design and documentation tool acquired by Oracle in 2017. Learn what it offered, its current status, and the 2026 shutdown timeline.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Apiary was an API design, mocking, and documentation platform founded in San Francisco in 2011 by Jan Moravec and Jakub Nesetril. It became known for creating and championing API Blueprint, an open-source, Markdown-based specification format for describing REST APIs, which it used to power live documentation, interactive mock servers, and automated testing directly from an API description. Before its acquisition, Apiary raised more than 8 million dollars in funding, including a 6.8 million dollar Series A in 2015, backed by investors such as Flybridge, Baseline Ventures, and Credo Ventures, and grew to support more than 160,000 to 590,000 APIs across roughly 486,000 registered users at its peak. Oracle acquired Apiary in January 2017 to bolster its API management and cloud integration portfolio, folding Apiary's design-and-mock capabilities into Oracle's broader API Platform Cloud Service and, later, Oracle Cloud Infrastructure. Paid Apiary subscription plans were deprecated back in 2018, meaning the product has effectively run as a free legacy tool for existing users for several years rather than an actively sold commercial product. As of 2026, Oracle has formally announced that Apiary is being retired, with a planned shutdown around September 2026, and Oracle is actively directing remaining users to migrate their API documentation, mock servers, and Blueprint files into other Oracle Cloud tooling before that date. In practical terms, Apiary is not a viable choice for anyone starting a new API documentation project today. It has had no meaningful new feature development in years, no modern pricing plans, and no long-term future as a standalone brand. Teams still using it for legacy documentation should treat this as an active migration deadline, moving specs to OpenAPI/Swagger-based tools such as SwaggerHub, Stoplight, Redocly, Postman, or Bump.sh, all of which offer comparable or superior design, mocking, and documentation capabilities with active support. For historical and research purposes, Apiary is notable as one of the earlier API-design-first platforms and as the origin of API Blueprint, which influenced how a generation of API tooling approached documentation-as-code, even though the OpenAPI/Swagger format has since become the dominant industry standard instead of API Blueprint.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'fe6fcb84-394f-4f51-a04f-2c92e13be0ff';

