-- ── App Annie ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$App Annie was a pioneering mobile app analytics and market intelligence platform founded in 2010; it rebranded to data.ai around 2021 to 2022, and data.ai was itself acquired by Sensor Tower in March 2024, so the App Annie name now redirects into Sensor Tower's product line.$q$, short_description),
  pricing_model = COALESCE($q$custom$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(2010, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$San Francisco, California, USA (originally founded in Beijing, China)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$App Annie in 2026: What Happened, data.ai and Sensor Tower$q$, seo_title),
  seo_meta_description = COALESCE($q$App Annie rebranded to data.ai, which Sensor Tower acquired in 2024. See the full history, what changed, and where to get mobile app analytics today.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$App Annie was one of the earliest and most prominent mobile app market intelligence platforms, founded in Beijing in 2010 by Bertrand Schmitt and Yann Lechelle, before later moving its headquarters to San Francisco around 2014 to 2015. The company built its business on estimating and selling data about app store downloads, revenue, rankings, and usage across the iOS App Store and Google Play, becoming a widely cited source for mobile industry benchmarking and competitive intelligence, and it raised well over 150 million dollars in venture funding over its history, at one point reaching a valuation in the billions of dollars. In late 2021 to early 2022, App Annie rebranded entirely to data.ai, a name change intended to reflect the company's pivot toward positioning itself as an AI-powered mobile data and analytics company rather than simply an 'app store analytics' brand; this rebrand also coincided with, and was related to, a 2021 SEC settlement in which App Annie and its then-CEO Bertrand Schmitt were charged with securities fraud for manipulating app performance estimates using confidential customer data, resulting in a 10 million dollar penalty. As data.ai, the company continued operating as an independent mobile analytics platform until March 2024, when it was acquired by Sensor Tower, a rival mobile app intelligence firm, in a deal with undisclosed terms; notably, data.ai had raised more than three times the total funding of its acquirer Sensor Tower before the deal closed. Following the acquisition, Sensor Tower absorbed part of data.ai's roughly 400-person team alongside layoffs, and has since worked to combine the two companies' underlying data panels and models into unified products, while for a period keeping both platforms available as nominally standalone offerings. As of 2026, the appannie.com domain redirects to www.data.ai, and the data.ai login page itself now displays a banner stating the company has been acquired by Sensor Tower, directing visitors to Sensor Tower's own site and products for current mobile app analytics services. In short, App Annie no longer exists as an independent, purchasable product or brand: it survives only as a historical name behind data.ai, which is now fully absorbed into Sensor Tower, the company that anyone researching gappsy.com listings should treat as the actual, current provider of this type of mobile app market intelligence data.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'b25e6074-563e-41e0-815c-ac0cbe553e43';

